async (page) => {
  // Try warp1 to see where it goes
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp1').click(), 300);
  });
  await page.waitForTimeout(3000);
  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  return JSON.stringify({pos});
}

async (page) => {
  // Set Hack attack style (index 0 = Strength + Defense)
  await page.evaluate(() => {
    try { window.game.player.setAttackStyle(0); } catch(e) {}
  });

  // Navigate east toward rats at (368, 870)
  // First move east to x=350, y=890 area
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 350, y: 892});
  await page.waitForTimeout(3000);

  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  return JSON.stringify({attackStyleSet: 'Hack(0)', tileClick: result, pos});
}
